+fn strsignal_realtime_signals_match_glibc_offsets() {
+    let check = |sig, expected: &[u8]| {
+        let msg = unsafe { strsignal(sig) };
+        assert!(!msg.is_null());
+        let s = unsafe { CStr::from_ptr(msg) };
+        assert_eq!(s.to_bytes(), expected, "strsignal({sig})");
